import anthropic, json, base64, pathlib
from openai import OpenAI

claude = anthropic.Anthropic()
oai    = OpenAI()

GEN_IMAGE_TOOL = {
    "name": "generate_image",
    "description": (
        "Generate an image from a text description. "
        "Use this when the user asks you to create, draw, or visualise something."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "prompt": {
                "type": "string",
                "description": "Detailed, descriptive prompt for the image generation model"
            },
            "style": {
                "type": "string",
                "enum": ["photorealistic", "illustration", "sketch", "oil painting"],
                "description": "Visual style for the image"
            }
        },
        "required": ["prompt"]
    }
}

def generate_image(prompt: str, style: str = "photorealistic") -> dict:
    full_prompt = f"{prompt}, {style} style"
    resp = oai.images.generate(
        model="dall-e-3",
        prompt=full_prompt,
        n=1,
        size="1024x1024",
        response_format="b64_json"
    )
    data = resp.data[0].b64_json
    out = pathlib.Path(f"generated_{abs(hash(prompt)) % 10000}.png")
    out.write_bytes(base64.b64decode(data))
    return {"saved_to": str(out), "revised_prompt": resp.data[0].revised_prompt}

messages = [{"role": "user", "content": "Create an illustration of a futuristic city skyline at night."}]

while True:
    response = claude.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        tools=[GEN_IMAGE_TOOL],
        messages=messages
    )
    messages.append({"role": "assistant", "content": response.content})

    if response.stop_reason == "end_turn":
        for b in response.content:
            if b.type == "text":
                print(b.text)
        break

    results = []
    for b in response.content:
        if b.type == "tool_use" and b.name == "generate_image":
            result = generate_image(**b.input)
            results.append({
                "type": "tool_result",
                "tool_use_id": b.id,
                "content": json.dumps(result)
            })
    messages.append({"role": "user", "content": results})

from openai import OpenAI
import pathlib

client = OpenAI()

# Image editing — requires a PNG with an alpha mask
def edit_image(image_path: str, mask_path: str, prompt: str) -> dict:
    with open(image_path, "rb") as img, open(mask_path, "rb") as mask:
        resp = client.images.edit(
            model="dall-e-2",
            image=img,
            mask=mask,
            prompt=prompt,
            n=1,
            size="1024x1024"
        )
    return {"url": resp.data[0].url}

# Image variation — same subject, different composition
def image_variation(image_path: str) -> dict:
    with open(image_path, "rb") as img:
        resp = client.images.create_variation(
            model="dall-e-2",
            image=img,
            n=1,
            size="512x512"
        )
    return {"url": resp.data[0].url}

# Both can be exposed as tools alongside generate_image
EDIT_TOOL = {
    "name": "edit_image",
    "description": "Edit a region of an existing image using a mask and text instruction.",
    "input_schema": {
        "type": "object",
        "properties": {
            "image_path": {"type": "string"},
            "mask_path":  {"type": "string"},
            "prompt":     {"type": "string"}
        },
        "required": ["image_path", "mask_path", "prompt"]
    }
}

VARIATION_TOOL = {
    "name": "image_variation",
    "description": "Create a variation of an existing image.",
    "input_schema": {
        "type": "object",
        "properties": {"image_path": {"type": "string"}},
        "required": ["image_path"]
    }
}

import replicate, anthropic, json

claude = anthropic.Anthropic()

def stable_diffusion(prompt: str, negative_prompt: str = "", steps: int = 30) -> dict:
    """Run Stable Diffusion XL via Replicate."""
    output = replicate.run(
        "stability-ai/sdxl:39ed52f2319f9b1779c33ded9ae21e51b26e8f3e77426e19dcae527eabcd2c94",
        input={
            "prompt": prompt,
            "negative_prompt": negative_prompt,
            "num_inference_steps": steps
        }
    )
    # output is a list of image URLs
    return {"image_url": output[0]}

SD_TOOL = {
    "name": "stable_diffusion",
    "description": "Generate an image with Stable Diffusion XL.",
    "input_schema": {
        "type": "object",
        "properties": {
            "prompt":          {"type": "string", "description": "Positive prompt"},
            "negative_prompt": {"type": "string", "description": "Elements to avoid"},
            "steps":           {"type": "integer", "description": "Inference steps (20-50)"}
        },
        "required": ["prompt"]
    }
}

messages = [{"role": "user", "content": "Generate a high-detail sketch of a medieval castle on a cliff."}]

response = claude.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=512,
    tools=[SD_TOOL],
    messages=messages
)

for b in response.content:
    if b.type == "tool_use":
        print(f"Calling {b.name} with: {b.input}")
        result = stable_diffusion(**b.input)
        print(f"Generated: {result['image_url']}")
